class Solution {
public:
    bool canConstruct(string s, int k) {
        unordered_map<char, int> freq;
        for (char c : s) {
            freq[c]++;
        }
        int oddCount = 0;
        for (auto it : freq) {
            if (it.second % 2 != 0) {
                oddCount++;
            }
        }
        return oddCount <= k;
    }
};
